    local signature = ngx.decode_base64(signature_b64)
    
    if not iv or not ciphertext or not signature then
        return nil, "base64 decode failed"
    end
    
    local h = hmac:new(sign_key, hmac.ALGOS.SHA256)
    h:update(iv_b64 .. "." .. ciphertext_b64)
    local expected_signature = h:final(nil, true)
    
    if signature ~= expected_signature then
        return nil, "signature verification failed"
    end
    
    local cipher = aes:new(enc_key, nil, aes.cipher(256, "cbc"), {iv = iv})
    local plaintext = cipher:decrypt(ciphertext)
    
