    h:update(iv_b64 .. "." .. ciphertext_b64)
    local signature = h:final(nil, true)
    local signature_b64 = ngx.encode_base64(signature)
    
    return iv_b64 .. "." .. ciphertext_b64 .. "." .. signature_b64
